/* Live rates: calls the Netlify function that proxies England Logistics.
   Returns {live:true,rates:[...]} on success, or null so callers fall back
   to the local estimate. Works on the deployed Netlify site; in the chat
   preview there's no backend so it simply returns null (estimate is used). */
const RATES_ENDPOINT="/.netlify/functions/quote";
async function getLiveRates(s,england){
  if(!england||!england.enabled) return null;
  const body={carriers:s.carriers||"fedex",fromZip:s.fromZip,toZip:s.toZip,fromCountry:s.fromCountry||"US",toCountry:s.toCountry||"US",residential:!!s.residential,signature:!!s.signature,signatureOption:s.signatureOption||(s.signature?"direct":"none"),saturdayDelivery:!!s.saturdayDelivery,insuranceAmount:s.insuranceAmount||null,packageTypeCode:s.packageTypeCode||"",pieces:(s.pieces||[]).map(p=>({weight:+p.weight||1,length:+p.L||12,width:+p.W||9,height:+p.H||4})),account:{base:england.base,apiKey:england.apiKey,customerId:england.customerId}};
  try{
    const ctrl=new AbortController();const t=setTimeout(()=>ctrl.abort(),12000);
    const r=await fetch(RATES_ENDPOINT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body),signal:ctrl.signal});
    clearTimeout(t);
    let data=null; try{data=await r.json();}catch(e){ try{data={error:await r.text()};}catch(e2){} }
    if(data&&typeof data==="object") return data;
    if(!r.ok) return {live:false,error:`Server ${r.status}`,rates:[]};
    return {live:false,error:"Empty response from server",rates:[]};
  }catch(e){ return {live:false,error:(e&&e.message)||"Network error",rates:[]}; }
}
const SHIP_ENDPOINT="/.netlify/functions/ship";
function acctOf(england){return {base:england.base,apiKey:england.apiKey,customerId:england.customerId,integrationId:england.integrationId};}
/* Per-client England accounts: if the client has their own England customer ID + API key
   (England bakes their markup into that account's rates), quotes and bookings run on THEIR
   account. Otherwise they fall back to the main account in Settings. The global "Use live
   England rates" toggle stays the master switch; base URL is inherited unless overridden. */
function englandFor(client,settings){const g=(settings&&settings.england)||{};const c=client&&client.england;if(c&&c.customerId&&c.apiKey)return {...g,...c,enabled:!!g.enabled};return g;}
/* ── shared per-order shipping helpers (used by Orders individual ship + Batch) ── */
async function ratesForOrder(o,opts,eng){
  const box=opts.box||{L:12,W:9,H:4};
  return getLiveRates({carriers:"fedex",fromZip:(opts.sender&&opts.sender.zip)||opts.fromZip,toZip:o.zip,toCountry:o.country||"US",residential:!!opts.residential,signature:opts.signatureOption?opts.signatureOption!=="none":!!opts.signature,signatureOption:opts.signatureOption||"none",saturdayDelivery:!!opts.saturdayDelivery,insuranceAmount:opts.insuranceAmount||null,packageTypeCode:opts.packageTypeCode||"",pieces:[{weight:opts.weightLb||o.weight||1,L:box.L,W:box.W,H:box.H}]},eng);
}
function orderToEngland(o,opts,sender,eng){
  const box=opts.box||{L:12,W:9,H:4};
  const wt=opts.weightLb||o.weight||1;
  const q=opts.quote||{};
  return {
    reference:opts.reference||o.name||"",orderNumber:o.name||"",invoiceNo:opts.invoiceNo||"",poNo:opts.poNo||"",shipmentDate:opts.shipDate||new Date().toISOString().slice(0,10),
    carrierCode:q.carrierCode,serviceCode:q.serviceCode,packageTypeCode:opts.packageTypeCode||q.packageTypeCode||"",
    shippingService:q.label,contentDescription:o.items||"Merchandise",
    residential:!!opts.residential,signatureOption:opts.signatureOption||"none",
    sender:{...(sender||{}),country:(sender&&sender.country)||"US"},
    receiver:{name:o.customer,company:o.company,address1:o.address1,address2:o.address2,city:o.city,state:o.state,zip:o.zip,country:o.country||"US",phone:o.phone,email:o.email},
    pieces:[{weight:wt,length:box.L,width:box.W,height:box.H}],
    providerAccountId:(eng&&eng.providerAccountId)||null,
  };
}
async function bookOrderLabel(o,opts,eng,sender){
  return shipCall({action:"ship",account:acctOf(eng),order:orderToEngland(o,opts,sender,eng)});
}
async function shipCall(payload){
  const ctrl=new AbortController();const t=setTimeout(()=>ctrl.abort(),20000);
  try{
    const r=await fetch(SHIP_ENDPOINT,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload),signal:ctrl.signal});
    clearTimeout(t);
    let data=null; try{data=await r.json();}catch(e){ try{data={ok:false,error:await r.text()};}catch(e2){data={ok:false,error:"Bad response"};} }
    return data||{ok:false,error:"Empty response"};
  }catch(e){clearTimeout(t);return {ok:false,error:(e&&e.message)||"Network error"};}
}
function openLabelPdf(base64){
  try{
    const bin=atob(base64);const len=bin.length;const bytes=new Uint8Array(len);
    for(let i=0;i<len;i++)bytes[i]=bin.charCodeAt(i);
    const blob=new Blob([bytes],{type:"application/pdf"});
    const url=URL.createObjectURL(blob);
    const w=window.open(url,"_blank");
    if(!w){const a=document.createElement("a");a.href=url;a.download="label.pdf";a.click();}
    setTimeout(()=>URL.revokeObjectURL(url),60000);
    return true;
  }catch(e){return false;}
}
// poll ship status until booked or timeout (~30s); calls onUpdate with each state
async function pollLabel(england,orderId,onUpdate){
  for(let i=0;i<10;i++){
    await new Promise(r=>setTimeout(r,3000));
    const res=await shipCall({action:"status",account:acctOf(england),orderId});
    if(res&&res.booked){onUpdate&&onUpdate(res);return res;}
  }
  return {ok:true,booked:false,timedOut:true};
}

