  const cubicVolume=(L>0&&W>0&&H>0)?Math.round(L*W*H):null;
  const li=Array.isArray(o.lineItems)?o.lineItems:[];
  const grams=li.reduce((a,x)=>a+((+x.grams||0)*(+x.quantity||1)),0);
