function ClientInvoices({invoices,setInvoices,shipments,client}){
  const live=shipments.filter(s=>s.status!=="Voided");
  const uninvoicedTotal=live.reduce((a,s)=>a+s.sell,0);
  const generate=()=>{if(!live.length)return;const num="INV-"+(1003+invoices.length);setInvoices(p=>[{id:"inv"+Date.now(),number:num,client:client.name,date:new Date().toLocaleDateString(),labels:live.length,amount:Math.round(uninvoicedTotal*100)/100,status:"Open"},...p]);};
  const markPaid=(id)=>setInvoices(p=>p.map(i=>i.id===id?{...i,status:"Paid"}:i));
  const open=invoices.filter(i=>i.status==="Open").reduce((a,i)=>a+i.amount,0);
  const exportCSV=()=>downloadCSV("shippingcloud-invoices.csv",[["Invoice","Client","Date","Labels","Amount","Status"],...invoices.map(i=>[i.number,i.client,i.date,i.labels,i.amount,i.status])]);
  return (<div className="max-w-3xl space-y-4">
    <div className="grid grid-cols-3 gap-3">
      <Stat2 label="Invoices" v={invoices.length}/>
      <Stat2 label="Open balance" v={money(open)} tone={open?"text-[#0086E0]":""}/>
      <Stat2 label="Billed all-time" v={money(invoices.reduce((a,i)=>a+i.amount,0))}/>
    </div>
    <div className="flex flex-wrap items-center gap-3">
      <h2 className="text-sm font-semibold text-stone-700 flex items-center gap-2"><Receipt className="w-4 h-4"/>Invoices</h2>
      <div className="flex-1"/>
      <button onClick={exportCSV} className="flex items-center gap-1.5 text-sm bg-stone-200 text-stone-700 rounded px-3 py-1.5 font-medium hover:bg-stone-300"><Download className="w-4 h-4"/>Export</button>
      <button onClick={generate} className="flex items-center gap-1.5 text-sm bg-stone-900 text-white rounded px-3 py-1.5 font-medium hover:bg-stone-800"><Plus className="w-4 h-4"/>Generate from shipments</button>
    </div>
    <div className="border border-stone-200 rounded-lg bg-white divide-y divide-stone-100">
      <div className="flex items-center gap-3 px-4 py-2 bg-stone-50 text-[11px] uppercase tracking-widest text-stone-400"><div className="w-24">Invoice</div><div className="flex-1">Client</div><div className="w-16 text-right">Labels</div><div className="w-24 text-right">Amount</div><div className="w-20 text-right">Status</div><div className="w-16"/></div>
      {invoices.length===0&&<div className="p-8 text-center text-sm text-stone-400">No invoices yet.</div>}
      {invoices.map(i=>(<div key={i.id} className="flex items-center gap-3 px-4 py-3">
        <div className="w-24 font-mono text-sm font-semibold">{i.number}</div>
        <div className="flex-1 min-w-0"><div className="text-sm truncate">{i.client}</div><div className="text-[11px] text-stone-400">{i.date}</div></div>
        <div className="w-16 text-right font-mono text-sm text-stone-500">{i.labels}</div>
        <div className="w-24 text-right font-mono text-sm font-semibold">{money(i.amount)}</div>
        <div className="w-20 text-right"><Badge tone={i.status==="Paid"?"green":"amber"}>{i.status}</Badge></div>
        <div className="w-16 text-right">{i.status==="Open"&&<button onClick={()=>markPaid(i.id)} className="text-xs text-[#0086E0] hover:underline">Mark paid</button>}</div>
      </div>))}
    </div>
  </div>);
}
// Minimal RFC-4180 CSV parser (handles quotes, embedded commas/newlines)
function parseCSVText(text){
  const s=String(text||"").replace(/\r\n/g,"\n").replace(/\r/g,"\n");
  const rows=[]; let row=[],cur="",q=false;
  for(let i=0;i<s.length;i++){ const c=s[i];
    if(q){ if(c==='"'){ if(s[i+1]==='"'){cur+='"';i++;} else q=false; } else cur+=c; }
    else if(c==='"')q=true;
    else if(c===","){row.push(cur);cur="";}
    else if(c==="\n"){row.push(cur);rows.push(row);row=[];cur="";}
    else cur+=c;
  }
  if(cur!==""||row.length){row.push(cur);rows.push(row);}
  return rows.filter(r=>r.some(c=>String(c).trim()!==""));
}
// Load pdf.js on demand from CDN so a customer can drop in a PDF invoice with no build dependency.
let _pdfjsPromise=null;
function loadPdfjs(){
  if(_pdfjsPromise) return _pdfjsPromise;
  const WK="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";
  _pdfjsPromise=new Promise((resolve,reject)=>{
    if(window.pdfjsLib){ try{window.pdfjsLib.GlobalWorkerOptions.workerSrc=WK;}catch(e){} return resolve(window.pdfjsLib); }
    const s=document.createElement("script"); s.src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
    s.onload=()=>{ try{ window.pdfjsLib.GlobalWorkerOptions.workerSrc=WK; resolve(window.pdfjsLib); }catch(e){ reject(e); } };
    s.onerror=()=>reject(new Error("Couldn't load the PDF reader."));
    document.head.appendChild(s);
  });
  return _pdfjsPromise;
}
async function extractPdfLines(file){
  const lib=await loadPdfjs();
  const buf=await file.arrayBuffer();
  const pdf=await lib.getDocument({data:buf}).promise;
  const lines=[];
  for(let p=1;p<=pdf.numPages;p++){
    const page=await pdf.getPage(p); const tc=await page.getTextContent();
    const rows={};
    tc.items.forEach(it=>{ const y=Math.round(it.transform[5]); (rows[y]=rows[y]||[]).push({x:it.transform[4],s:it.str}); });
    Object.keys(rows).map(Number).sort((a,b)=>b-a).forEach(y=>{ const ln=rows[y].sort((a,b)=>a.x-b.x).map(i=>i.s).join(" ").replace(/\s+/g," ").trim(); if(ln)lines.push(ln); });
  }
  return lines;
}
const TRACK_RE=/\b(1Z[0-9A-Z]{16}|\d{20,22}|\d{15}|\d{12})\b/;
const MONEY_RE=/-?\$?\s?\d{1,3}(?:,\d{3})+(?:\.\d{2})|-?\$?\s?\d+\.\d{2}/g;
function moneyVal(str){ const n=parseFloat(String(str).replace(/[^0-9.\-]/g,"")); return isNaN(n)?0:n; }
// Best-effort PDF invoice parse: group text into per-tracking blocks and pull amount / weight / dims / charge lines.
function parsePdfInvoice(lines){
  const idxs=[]; lines.forEach((ln,i)=>{ const m=ln.match(TRACK_RE); if(m)idxs.push({i,tracking:m[1]}); });
  const groups={};
  for(let k=0;k<idxs.length;k++){
    const start=idxs[k].i, tracking=idxs[k].tracking;
    const end=k+1<idxs.length?idxs[k+1].i:Math.min(lines.length,start+12);
    const blockLines=lines.slice(start,end); const block=blockLines.join("  ");
    const key=tracking.replace(/\s+/g,"").toUpperCase();
    if(!groups[key])groups[key]={tracking,billed:0,weight:null,dimL:null,dimW:null,dimH:null,charges:[]};
    let amt=null;
    const nc=block.match(/(?:net charge|total charge|amount due|net amount)[^0-9\-$]*(-?\$?\s?\d[\d,]*\.\d{2})/i);
    if(nc)amt=moneyVal(nc[1]);
    if(amt==null){ const monies=(block.match(MONEY_RE)||[]).map(moneyVal).filter(n=>n!==0); if(monies.length)amt=Math.max(...monies); }
    if(amt!=null)groups[key].billed=Math.round((groups[key].billed+amt)*100)/100;
    const wm=block.match(/(?:billed|rated|actual)\s*weight[^0-9]*(\d+(?:\.\d+)?)/i)||block.match(/(\d+(?:\.\d+)?)\s*lbs?\b/i);
    if(wm&&groups[key].weight==null){ const w=parseFloat(wm[1]); if(w>0)groups[key].weight=w; }
    const dm=block.match(/(\d+(?:\.\d+)?)\s*[x×]\s*(\d+(?:\.\d+)?)\s*[x×]\s*(\d+(?:\.\d+)?)/i);
    if(dm&&groups[key].dimL==null){ groups[key].dimL=+dm[1]; groups[key].dimW=+dm[2]; groups[key].dimH=+dm[3]; }
    const KWTXT=/(additional handling|address correction|residential|delivery area|dimensional|dim weight|oversize|unauthorized|adjustment|correction|peak|fuel|reweigh|signature|saturday)/i;
    blockLines.forEach(ln=>{ if(KWTXT.test(ln)){ const mm=ln.match(MONEY_RE); groups[key].charges.push({desc:ln.replace(MONEY_RE,"").replace(/\s+/g," ").trim().slice(0,70),amount:mm?moneyVal(mm[mm.length-1]):0}); } });
  }
  return groups;
}
const AUDIT_CANDS={
  tracking:["tracking number","tracking id","tracking","track id","air waybill","express or ground tracking","ground tracking"],
  amount:["net charge amount","net charge","net amount","billed charge","total charge amount","total charge","net","amount"],
  weight:["billed weight","rated weight","bill weight","original weight","actual weight","weight"],
  desc:["tracking id charge description","charge description","charge category detail","charge category","charge classification","description"],
  dimL:["dim length","length","dim l"],
  dimW:["dim width","width","dim w"],
  dimH:["dim height","height","dim h"],
};
function auditFindCol(headers,cands){ for(const cand of cands){ const i=headers.findIndex(h=>String(h||"").toLowerCase().trim().includes(cand)); if(i>=0)return i; } return -1; }
function buildCsvGroups(data,map){
  const {tracking:tc,amount:ac,weight:wc,desc:dc,dimL:lc,dimW:wcc,dimH:hc}=map;
  const numOf=v=>{const n=parseFloat(String(v==null?"":v).replace(/[^0-9.\-]/g,""));return isNaN(n)?0:n;};
  const norm=t=>String(t||"").replace(/\s+/g,"").toUpperCase();
  const groups={};
  for(const r of data){ const t=norm(r[tc]); if(!t)continue;
    if(!groups[t])groups[t]={tracking:String(r[tc]).trim(),billed:0,weight:null,dimL:null,dimW:null,dimH:null,charges:[]};
    const amt=Math.round(numOf(r[ac])*100)/100; groups[t].billed=Math.round((groups[t].billed+amt)*100)/100;
    if(wc>=0&&groups[t].weight==null){ const w=numOf(r[wc]); if(w>0)groups[t].weight=w; }
    if(lc>=0&&groups[t].dimL==null){ const L=numOf(r[lc]),W=wcc>=0?numOf(r[wcc]):0,H=hc>=0?numOf(r[hc]):0; if(L>0){groups[t].dimL=L;groups[t].dimW=W;groups[t].dimH=H;} }
    if(dc>=0){ const d=String(r[dc]||"").trim(); if(d)groups[t].charges.push({desc:d,amount:amt}); }
  }
  return groups;
}
function CarrierAudit({shipments}){
  const [groups,setGroups]=useState(null);
  const [source,setSource]=useState("");
  const [name,setName]=useState("");
  const [busy,setBusy]=useState(false);
  const [err,setErr]=useState("");
  const [note,setNote]=useState("");
  const [csv,setCsv]=useState(null);
  const [map,setMap]=useState({tracking:-1,amount:-1,weight:-1,desc:-1,dimL:-1,dimW:-1,dimH:-1});
  const [open,setOpen]=useState(null);
  const [overrides,setOverrides]=useState({});
  const norm=t=>String(t||"").replace(/\s+/g,"").toUpperCase();
  const onFile=async(e)=>{
    const f=e.target.files&&e.target.files[0]; if(!f)return; setErr("");setNote("");setOverrides({});setOpen(null);setName(f.name);
    const isPdf=/\.pdf$/i.test(f.name)||f.type==="application/pdf";
    if(isPdf){
      setBusy(true);setSource("pdf");setCsv(null);
      try{ const lines=await extractPdfLines(f); const g=parsePdfInvoice(lines);
        if(!Object.keys(g).length){ setErr("Couldn't find tracking numbers in that PDF. If it's a scanned image, download a CSV from your carrier's billing site instead."); setGroups(null); }
        else { setGroups(g); setNote("Read from PDF automatically — please double-check the billed amounts below and correct any that look off."); }
      }catch(x){ setErr("Couldn't read that PDF. Try the CSV export from FedEx Billing Online or the UPS Billing Center."); setGroups(null); }
      setBusy(false);
    } else {
      setSource("csv");
      const r=new FileReader();
      r.onload=()=>{ try{
        const rows=parseCSVText(r.result); if(rows.length<2){setErr("That file has no data rows.");return;}
        const headers=rows[0].map(h=>String(h||"").trim()); const data=rows.slice(1);
        const m={tracking:auditFindCol(headers,AUDIT_CANDS.tracking),amount:auditFindCol(headers,AUDIT_CANDS.amount),weight:auditFindCol(headers,AUDIT_CANDS.weight),desc:auditFindCol(headers,AUDIT_CANDS.desc),dimL:auditFindCol(headers,AUDIT_CANDS.dimL),dimW:auditFindCol(headers,AUDIT_CANDS.dimW),dimH:auditFindCol(headers,AUDIT_CANDS.dimH)};
        setCsv({headers,data}); setMap(m);
        if(m.tracking<0||m.amount<0){ setGroups(null); setNote("Pick which columns hold the tracking # and amount below."); }
        else { setGroups(buildCsvGroups(data,m)); setNote(""); }
      }catch(x){ setErr("Couldn't read that file — make sure it's a CSV or PDF export."); } };
      r.onerror=()=>setErr("Couldn't read that file.");
      r.readAsText(f);
    }
  };
  useEffect(()=>{ if(source==="csv"&&csv&&map.tracking>=0&&map.amount>=0){ setGroups(buildCsvGroups(csv.data,map)); setNote(""); } },[map,csv,source]);
  const recon=useMemo(()=>{
    if(!groups) return null;
    const byTrack={}; for(const s of shipments){ if(s.tracking)byTrack[norm(s.tracking)]=s; }
    const KW=[["additional handling","Additional handling fee"],["address correction","Address correction"],["residential","Residential surcharge"],["delivery area","Delivery-area surcharge"],["dimensional","Dimensional weight applied"],["dim weight","Dimensional weight applied"],["oversize","Oversize package"],["unauthorized","Unauthorized package"],["peak","Peak-season surcharge"],["adjustment","Carrier adjustment"],["correction","Carrier correction"],["signature","Signature fee"],["saturday","Saturday surcharge"]];
    const entries=Object.keys(groups).map(k=>{
      const g=groups[k]; const s=byTrack[k]; const ov=overrides[k]||{};
      const billed=ov.billed!=null?Math.round(ov.billed*100)/100:Math.round(g.billed*100)/100;
      const quoted=s?Math.round((s.sell||0)*100)/100:null;
      const diff=quoted!=null?Math.round((billed-quoted)*100)/100:null;
      const qWeight=s?(+s.weight||null):null;
      const sd=s?(s.dims||(s.pieces&&s.pieces[0])||{}):{}; const qL=+sd.L||null,qW=+sd.W||null,qH=+sd.H||null;
      const reasons=[];
      if(g.weight!=null&&qWeight!=null&&g.weight>qWeight+0.01) reasons.push({t:"reweigh",label:`Reweighed by carrier: ${qWeight} → ${g.weight} lb`});
      if(g.dimL!=null&&qL!=null&&(g.dimL>qL+0.5||g.dimW>qW+0.5||g.dimH>qH+0.5)) reasons.push({t:"dim",label:`Larger size billed: ${qL}×${qW}×${qH} → ${g.dimL}×${g.dimW}×${g.dimH} in`});
      const cl=g.charges.map(c=>String(c.desc).toLowerCase()).join("  ");
      for(const [k2,label] of KW){ if(cl.includes(k2)&&!reasons.some(r=>r.label===label)) reasons.push({t:"fee",label}); }
      if(!reasons.length&&diff!=null&&diff>0.01) reasons.push({t:"other",label:"Billed higher than quoted — reason not itemized on invoice"});
      return {key:k,tracking:g.tracking,ship:s,matched:!!s,billed,billedWeight:g.weight,quoted,qWeight,diff,
        diffPct:quoted?Math.round((billed-quoted)/quoted*1000)/10:null,charges:g.charges,reasons,status:ov.status||"new"};
    }).sort((a,b)=>Math.abs(b.diff||0)-Math.abs(a.diff||0));
    const matched=entries.filter(e=>e.matched);
    const sum={ lines:entries.length, matched:matched.length, unmatched:entries.length-matched.length,
      quoted:Math.round(matched.reduce((a,e)=>a+(e.quoted||0),0)*100)/100,
      billed:Math.round(entries.reduce((a,e)=>a+e.billed,0)*100)/100,
      diff:Math.round(matched.reduce((a,e)=>a+(e.diff||0),0)*100)/100,
      higher:matched.filter(e=>(e.diff||0)>0.01).length,
      disputed:entries.filter(e=>e.status==="disputed").length };
    return {entries,sum};
  },[groups,overrides,shipments]);
  const setBilled=(k,v)=>setOverrides(o=>({...o,[k]:{...o[k],billed:v===""?null:(+v||0)}}));
  const setStatus=(k,st)=>setOverrides(o=>({...o,[k]:{...o[k],status:(o[k]&&o[k].status)===st?"new":st}}));
  const exportReport=()=>{
    if(!recon)return;
    const rows=[["Tracking","Service","Recipient","Ship date","You were quoted","Invoice billed","Difference","Difference %","Quoted weight","Billed weight","Why it differs","Your status"]];
    recon.entries.forEach(e=>{ const s=e.ship||{}; rows.push([e.tracking,s.service||"",(s.recipient&&s.recipient.name)||"",s.date||"",e.quoted==null?"":e.quoted,e.billed,e.diff==null?"":e.diff,e.diffPct!=null?e.diffPct+"%":"",e.qWeight==null?"":e.qWeight,e.billedWeight==null?"":e.billedWeight,e.reasons.map(r=>r.label).join("; ")||(e.matched?"Matches your quote":"No matching shipment found"),e.status]); });
    downloadCSV("shipping-cost-audit.csv",rows);
  };
  const colSel=(field,label)=>csv?(
    <div className="flex items-center gap-1.5"><span className="text-[11px] uppercase tracking-widest text-stone-400">{label}</span>
      <select value={map[field]} onChange={e=>setMap(m=>({...m,[field]:+e.target.value}))} className="bg-white border border-stone-300 rounded px-2 py-1 text-[13px] outline-none focus:border-[#0099FF]">
        <option value={-1}>—</option>
        {csv.headers.map((h,i)=><option key={i} value={i}>{h||("Column "+(i+1))}</option>)}
      </select>
    </div>
  ):null;
  const dTone=(v)=>v==null?"text-stone-400":v>0.01?"text-rose-600":v<-0.01?"text-emerald-600":"text-stone-500";
  return (<div className="space-y-4">
    <div>
      <h2 className="text-base font-semibold text-stone-800 flex items-center gap-2"><ScanLine className="w-4 h-4"/>Shipping cost audit</h2>
      <p className="text-sm text-stone-500 mt-1">Paid one price when you booked, but the carrier billed something different? Upload your carrier invoice (PDF or CSV) and we'll match every tracking number back to what you were quoted, then show exactly what changed — a reweigh, larger dimensions, an address correction, additional handling — and by how much.</p>
    </div>
    <div className="border-2 border-dashed border-stone-300 rounded-xl bg-white p-6 text-center">
      {busy?<Loader2 className="w-6 h-6 text-[#0086E0] mx-auto mb-2 animate-spin"/>:<Upload className="w-6 h-6 text-stone-400 mx-auto mb-2"/>}
      <label className="inline-block cursor-pointer text-sm bg-[#0086E0] text-white rounded-lg px-4 py-2 font-medium hover:bg-[#0072BE]">
        {groups?"Choose a different invoice":"Upload invoice (PDF or CSV)"}
        <input type="file" accept=".csv,.pdf,text/csv,application/pdf" onChange={onFile} className="hidden"/>
      </label>
      {name&&<div className="text-[13px] text-stone-500 mt-2 flex items-center justify-center gap-1.5"><FileText className="w-3.5 h-3.5"/>{name}{source==="pdf"?" · PDF":""}</div>}
      {busy&&<div className="text-[13px] text-stone-500 mt-2">Reading the PDF…</div>}
      {err&&<div className="text-[13px] text-rose-600 mt-2">{err}</div>}
      {note&&!err&&<div className="text-[13px] text-amber-700 mt-2">{note}</div>}
      <div className="text-[12px] text-stone-400 mt-2">CSV is the most accurate — FedEx Billing Online and the UPS Billing Center both let you download the invoice as CSV. PDF works too and is read automatically.</div>
    </div>
    {csv&&(<div className="bg-white border border-stone-200 rounded-lg p-3 flex flex-wrap items-center gap-x-4 gap-y-2">
      <span className="text-[11px] uppercase tracking-widest text-stone-500 font-medium">Columns</span>
      {colSel("tracking","Tracking")}{colSel("amount","Amount")}{colSel("weight","Weight")}{colSel("dimL","Length")}{colSel("dimW","Width")}{colSel("dimH","Height")}{colSel("desc","Charge")}
    </div>)}
    {recon&&recon.entries&&recon.entries.length>0&&(<>
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
        <Stat2 label="Shipments on invoice" v={recon.sum.lines}/>
        <Stat2 label="Total difference" v={(recon.sum.diff>=0?"+":"−")+money(Math.abs(recon.sum.diff)).slice(1)} tone={recon.sum.diff>0.01?"text-rose-600":recon.sum.diff<-0.01?"text-emerald-600":""}/>
        <Stat2 label="Billed higher" v={recon.sum.higher} tone={recon.sum.higher?"text-rose-600":""}/>
        <Stat2 label="Flagged to dispute" v={recon.sum.disputed} tone={recon.sum.disputed?"text-amber-600":""}/>
      </div>
      <div className="flex flex-wrap items-center gap-3">
        <div className="text-[13px] text-stone-500">You were quoted <b className="text-stone-700 font-mono">{money(recon.sum.quoted)}</b> · Invoice billed <b className="text-stone-700 font-mono">{money(recon.sum.billed)}</b>{recon.sum.unmatched>0?<> · <span className="text-stone-400">{recon.sum.unmatched} not found in your shipments</span></>:null}</div>
        <div className="flex-1"/>
        <button onClick={exportReport} className="flex items-center gap-1.5 text-sm bg-stone-900 text-white rounded px-3 py-1.5 font-medium hover:bg-stone-800"><Download className="w-4 h-4"/>Export report</button>
      </div>
      <div className="border border-stone-200 rounded-lg bg-white overflow-hidden">
        <div className="flex items-center gap-3 px-3 py-2 bg-stone-50 text-[11px] uppercase tracking-widest text-stone-400"><div className="w-4"/><div className="flex-1">Tracking / shipment</div><div className="w-24 text-right">Weight</div><div className="w-24 text-right">You paid</div><div className="w-24 text-right">Billed</div><div className="w-24 text-right">Difference</div></div>
        {recon.entries.map(e=>{ const isO=open===e.key; return (
          <div key={e.key} className={`border-t border-stone-100 ${e.status==="disputed"?"bg-amber-50/40":e.status==="accepted"?"bg-emerald-50/30":""}`}>
            <div onClick={()=>setOpen(isO?null:e.key)} className="flex items-center gap-3 px-3 py-2.5 cursor-pointer hover:bg-stone-50">
              <ChevronRight className={`w-4 h-4 text-stone-400 shrink-0 transition-transform ${isO?"rotate-90":""}`}/>
              <div className="flex-1 min-w-0">
                <div className="text-sm font-mono truncate flex items-center gap-2 flex-wrap">{e.tracking}{!e.matched&&<Badge tone="stone">no shipment</Badge>}{e.status==="disputed"&&<Badge tone="amber">disputing</Badge>}{e.status==="accepted"&&<Badge tone="green">accepted</Badge>}{e.reasons.map((r,i)=><Badge key={i} tone={r.t==="reweigh"||r.t==="dim"?"amber":r.t==="other"?"stone":"rose"}>{r.label}</Badge>)}</div>
                <div className="text-[12px] text-stone-500 truncate">{e.matched?`${(e.ship.recipient&&e.ship.recipient.name)||"—"} · ${e.ship.service||""} · ${e.ship.date||""}`:"Not found in your shipment history"}</div>
              </div>
              <div className="w-24 text-right font-mono text-[13px] text-stone-500">{e.billedWeight!=null?(e.qWeight!=null&&e.billedWeight>e.qWeight+0.01?<span className="text-amber-600">{e.qWeight}→{e.billedWeight}</span>:e.billedWeight)+" lb":<span className="text-stone-300">—</span>}</div>
              <div className="w-24 text-right font-mono text-[13px] text-stone-600">{e.quoted!=null?money(e.quoted):<span className="text-stone-300">—</span>}</div>
              <div className="w-24 text-right" onClick={ev=>ev.stopPropagation()}><input value={(overrides[e.key]&&overrides[e.key].billed!=null)?overrides[e.key].billed:e.billed} onChange={ev=>setBilled(e.key,ev.target.value)} className="w-20 text-right font-mono text-[13px] text-stone-800 bg-transparent border border-transparent hover:border-stone-200 focus:border-[#0099FF] rounded px-1 py-0.5 outline-none"/></div>
              <div className={`w-24 text-right font-mono text-sm font-semibold ${dTone(e.diff)}`}>{e.diff==null?"—":(e.diff>0?"+":e.diff<0?"−":"")+money(Math.abs(e.diff)).slice(1)}{e.diffPct!=null?<span className="block text-[10px] font-normal opacity-70">{e.diffPct>0?"+":""}{e.diffPct}%</span>:null}</div>
            </div>
            {isO&&(<div className="px-10 pb-3 pt-1 space-y-2 bg-stone-50/50">
              {e.matched?<div className="grid grid-cols-2 gap-x-6 gap-y-1 text-[13px] max-w-sm">
                <div className="text-stone-500">You were quoted</div><div className="font-mono text-right">{e.quoted!=null?money(e.quoted):"—"}</div>
                <div className="text-stone-500">Carrier billed</div><div className="font-mono text-right">{money(e.billed)}</div>
                <div className="text-stone-500 font-medium">Difference</div><div className={`font-mono text-right font-semibold ${dTone(e.diff)}`}>{e.diff==null?"—":(e.diff>0?"+":e.diff<0?"−":"")+money(Math.abs(e.diff)).slice(1)}</div>
              </div>:<div className="text-[13px] text-stone-500 max-w-md">This tracking number isn't in your shipment history, so there's nothing to compare it against.</div>}
              {e.reasons.length>0&&<div className="pt-1"><div className="text-[11px] uppercase tracking-widest text-stone-400 mb-1">Why it's different</div>{e.reasons.map((r,i)=><div key={i} className="text-[13px] text-stone-700">• {r.label}</div>)}</div>}
              {e.charges.length>0&&<div className="pt-1"><div className="text-[11px] uppercase tracking-widest text-stone-400 mb-1">Billed charge lines</div>{e.charges.map((c,i)=><div key={i} className="flex justify-between text-[13px] text-stone-600 max-w-md"><span className="truncate pr-3">{c.desc}</span><span className="font-mono shrink-0">{c.amount?money(c.amount):""}</span></div>)}</div>}
              {e.matched&&<div className="flex items-center gap-2 pt-1">
                <button onClick={()=>setStatus(e.key,"accepted")} className={`text-[13px] rounded px-3 py-1 font-medium border ${e.status==="accepted"?"bg-emerald-600 text-white border-emerald-600":"bg-white text-stone-600 border-stone-300 hover:bg-stone-50"}`}>Looks right</button>
                <button onClick={()=>setStatus(e.key,"disputed")} className={`text-[13px] rounded px-3 py-1 font-medium border ${e.status==="disputed"?"bg-amber-500 text-white border-amber-500":"bg-white text-stone-600 border-stone-300 hover:bg-stone-50"}`}>Flag to dispute</button>
                <span className="text-[12px] text-stone-400">Edit the billed amount above if the invoice reads differently.</span>
              </div>}
            </div>)}
          </div>
        );})}
      </div>
    </>)}
    {recon&&recon.entries&&recon.entries.length===0&&<div className="text-sm text-stone-500 bg-stone-50 border border-stone-200 rounded-lg p-4">No tracking numbers found to compare. If this is a CSV, check the column mapping above.</div>}
  </div>);
}

/* ════════ LEDGER ════════ */
function Ledger({ledger,addLedger}){
  const [funds,setFunds]=useState("");
  const [adj,setAdj]=useState({amount:"",note:""});
  const balance=ledger.reduce((a,e)=>a+e.amount,0);
  const addFunds=()=>{const amt=+funds;if(!amt)return;addLedger({type:"Funds added",ref:"Manual deposit",amount:Math.abs(amt)});setFunds("");};
  const addAdj=()=>{const amt=+adj.amount;if(!amt)return;addLedger({type:"Adjustment",ref:adj.note||"Adjustment",amount:amt});setAdj({amount:"",note:""});};
  // running balance (oldest first), display newest first
  let run=0; const withRun=[...ledger].reverse().map(e=>{run+=e.amount;return {...e,run};}).reverse();
  return (<div className="max-w-3xl space-y-4">
    <div className="grid sm:grid-cols-3 gap-3">
      <div className="border border-stone-200 rounded-xl bg-white p-4 sm:col-span-1"><div className="text-[11px] uppercase tracking-widest text-stone-400">Account balance</div><div className={`text-3xl font-bold mt-1 ${balance<0?"text-rose-600":"text-stone-900"}`}>{money(balance)}</div></div>
      <div className="border border-stone-200 rounded-xl bg-white p-4"><div className="text-[11px] uppercase tracking-widest text-stone-400 mb-1">Add funds</div><div className="flex gap-2"><div className="relative flex-1"><DollarSign className="w-4 h-4 absolute left-2 top-2.5 text-stone-400"/><input type="number" value={funds} onChange={e=>setFunds(e.target.value)} placeholder="100.00" className="w-full bg-white border border-stone-200 rounded pl-7 pr-2 py-2 text-sm font-mono outline-none focus:border-[#0099FF]"/></div><button onClick={addFunds} className="text-sm bg-stone-900 text-white rounded px-3 py-2 font-medium hover:bg-stone-800">Add</button></div></div>
      <div className="border border-stone-200 rounded-xl bg-white p-4"><div className="text-[11px] uppercase tracking-widest text-stone-400 mb-1">Adjustment</div><div className="flex gap-2"><input type="number" value={adj.amount} onChange={e=>setAdj({...adj,amount:e.target.value})} placeholder="±0.00" className="w-20 bg-white border border-stone-200 rounded px-2 py-2 text-sm font-mono outline-none focus:border-[#0099FF]"/><input value={adj.note} onChange={e=>setAdj({...adj,note:e.target.value})} placeholder="note" className="flex-1 min-w-0 bg-white border border-stone-200 rounded px-2 py-2 text-sm outline-none focus:border-[#0099FF]"/><button onClick={addAdj} className="text-sm bg-stone-200 text-stone-700 rounded px-3 py-2 font-medium hover:bg-stone-300">Post</button></div></div>
    </div>
    <div className="border border-stone-200 rounded-lg bg-white divide-y divide-stone-100">
      <div className="flex items-center gap-3 px-4 py-2 bg-stone-50 text-[11px] uppercase tracking-widest text-stone-400"><div className="w-24">Date</div><div className="w-36">Type</div><div className="flex-1">Reference</div><div className="w-24 text-right">Amount</div><div className="w-24 text-right">Balance</div></div>
      {withRun.length===0&&<div className="p-8 text-center text-sm text-stone-400">No transactions yet.</div>}
      {withRun.map(e=>(<div key={e.id} className="flex items-center gap-3 px-4 py-2.5">
        <div className="w-24 text-sm font-mono text-stone-500">{e.date}</div>
        <div className="w-36 text-sm">{e.type}</div>
        <div className="flex-1 min-w-0 text-sm text-stone-500 truncate">{e.ref}</div>
        <div className={`w-24 text-right font-mono text-sm ${e.amount<0?"text-rose-600":"text-emerald-600"}`}>{e.amount<0?"−":"+"}{money(Math.abs(e.amount))}</div>
        <div className="w-24 text-right font-mono text-sm text-stone-700">{money(e.run)}</div>
      </div>))}
    </div>
  </div>);
}


function Clients({clients,setClients}){
  const set=(id,v)=>setClients(cs=>cs.map(c=>c.id===id?{...c,markup:Math.max(0,v)}:c));
  return (<div className="space-y-3 max-w-2xl"><p className="text-sm text-stone-500">Markup is your cut on every label this client ships. Customers never see it.</p>
    {clients.map(c=>(<div key={c.id} className="border border-stone-200 rounded-lg bg-white p-4 flex items-center gap-4"><div className="w-9 h-9 rounded bg-stone-100 flex items-center justify-center text-[#0086E0] font-semibold">{c.name[0]}</div><div className="flex-1"><div className="font-medium">{c.name}</div><div className="text-[11px] text-stone-400 font-mono">origin {c.origin}</div></div><button onClick={()=>set(c.id,c.markup-1)} className="w-7 h-7 rounded bg-stone-200 hover:bg-stone-300">–</button><div className="w-14 text-center font-mono text-[#0086E0] font-semibold">{c.markup}%</div><button onClick={()=>set(c.id,c.markup+1)} className="w-7 h-7 rounded bg-stone-200 hover:bg-stone-300">+</button></div>))}
  </div>);
}

/* ════════ PRIMITIVES ════════ */
// Smart paste: turn a pasted contact/address blob into structured fields.
const US_STATE_ABBRS=new Set(["AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY","DC","PR"]);
const STATE_NAME_TO_ABBR={"alabama":"AL","alaska":"AK","arizona":"AZ","arkansas":"AR","california":"CA","colorado":"CO","connecticut":"CT","delaware":"DE","florida":"FL","georgia":"GA","hawaii":"HI","idaho":"ID","illinois":"IL","indiana":"IN","iowa":"IA","kansas":"KS","kentucky":"KY","louisiana":"LA","maine":"ME","maryland":"MD","massachusetts":"MA","michigan":"MI","minnesota":"MN","mississippi":"MS","missouri":"MO","montana":"MT","nebraska":"NE","nevada":"NV","new hampshire":"NH","new jersey":"NJ","new mexico":"NM","new york":"NY","north carolina":"NC","north dakota":"ND","ohio":"OH","oklahoma":"OK","oregon":"OR","pennsylvania":"PA","rhode island":"RI","south carolina":"SC","south dakota":"SD","tennessee":"TN","texas":"TX","utah":"UT","vermont":"VT","virginia":"VA","washington":"WA","west virginia":"WV","wisconsin":"WI","wyoming":"WY","district of columbia":"DC","puerto rico":"PR"};
function parseCSZ(seg){
  const out={}; seg=String(seg||"").trim();
  const zip=seg.match(/\b(\d{5})(?:-\d{4})?\b/);
  if(zip){ out.zip=zip[1]; seg=(seg.slice(0,zip.index)+" "+seg.slice(zip.index+zip[0].length)).trim(); }
  seg=seg.replace(/[,\s]+$/,"").trim();
  const ab=seg.match(/(?:^|[\s,])([A-Za-z]{2})$/);
  if(ab&&US_STATE_ABBRS.has(ab[1].toUpperCase())){ out.state=ab[1].toUpperCase(); seg=seg.slice(0,seg.length-ab[1].length).replace(/[,\s]+$/,"").trim(); }
  else { const fn=Object.keys(STATE_NAME_TO_ABBR).sort((a,b)=>b.length-a.length).find(n=>new RegExp("(?:^|[\\s,])"+n+"$","i").test(seg)); if(fn){ out.state=STATE_NAME_TO_ABBR[fn]; seg=seg.replace(new RegExp(fn+"$","i"),"").replace(/[,\s]+$/,"").trim(); } }
  seg=seg.replace(/[,\s]+$/,"").trim();
  if(seg) out.city=seg.replace(/,/g,"").trim();
  return out;
}
function stripTrailingCity(addr,city){
  if(!addr||!city) return addr;
  const esc=String(city).trim().replace(/[.*+?^${}()|[\]\\]/g,"\\$&");
  const out=String(addr).replace(new RegExp("[\\s,]*"+esc+"\\s*,?\\s*$","i"),"").replace(/[\s,]+$/,"").trim();
  return out||addr;
}
function parseAddressBlob(raw){
  const out={};
  let text=String(raw||"").replace(/\r/g,"").trim();
  if(!text) return out;
  // un-glue a lost line break like "960 SAmerican Fork" → "960 S American Fork"
  text=text.replace(/\b([NSEW])([A-Z][a-z])/g,"$1 $2");
  const em=text.match(/[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}/i);
  if(em){ out.email=em[0]; text=text.replace(em[0]," "); }
  const ph=text.match(/(\+?1[\s.\-]?)?\(?\d{3}\)?[\s.\-]?\d{3}[\s.\-]?\d{4}(?!\d)/);
  if(ph&&ph[0].replace(/\D/g,"").length>=10){ out.phone=ph[0].replace(/\s+/g," ").trim(); text=text.replace(ph[0]," "); }
  const ctry=text.match(/\b(United States of America|United States|U\.?S\.?A\.?|USA|Canada|Mexico)\b/i);
  if(ctry){ const c=ctry[0].toLowerCase(); out.country=/can/.test(c)?"Canada":(/mex/.test(c)?"Mexico":"United States"); text=text.replace(ctry[0]," "); }
  let lines=text.split(/\n+/).map(s=>s.replace(/[ \t]+/g," ").trim()).filter(Boolean);
  if(lines.length===1&&lines[0].includes(",")) lines=lines[0].split(",").map(s=>s.trim()).filter(Boolean);
  let cszIdx=lines.findIndex(l=>/\b\d{5}(-\d{4})?\b/.test(l));
  if(cszIdx>=0){
    let csz=parseCSZ(lines[cszIdx]);
    if(!csz.city&&cszIdx>0&&!/^\s*\d/.test(lines[cszIdx-1])){ const merged=parseCSZ(lines[cszIdx-1]+" "+lines[cszIdx]); if(merged.city){ csz=merged; lines.splice(cszIdx-1,1); cszIdx--; } }
    if(csz.zip)out.zip=csz.zip; if(csz.state)out.state=csz.state; if(csz.city)out.city=csz.city;
    lines.splice(cszIdx,1);
  }
  const stRe=/^\s*(\d+[-\w]*|(?:po|p\.o\.)\s*box)\s+\S/i;
  const aptRe=/\b(apt|apartment|suite|ste|unit|bldg|building|floor|fl|rm|room|dept)\b\.?\s*\S|#\s*\w/i;
  const addrIdx=lines.findIndex(l=>stRe.test(l));
  if(addrIdx>=0){ out.address1=lines[addrIdx]; lines.splice(addrIdx,1); }
  const aptIdx=lines.findIndex(l=>aptRe.test(l));
  if(aptIdx>=0){ out.address2=lines[aptIdx]; lines.splice(aptIdx,1); }
  const compRe=/\b(inc|llc|corp|corporation|company|co|ltd|limited|lp|llp|plc|group|holdings|enterprises|services|logistics|industries|systems|solutions|associates|partners|freight|shipping|warehouse|distribution)\b\.?/i;
  const rem=lines.filter(Boolean);
  if(rem.length){
    let ci=rem.findIndex(l=>compRe.test(l));
    if(ci>=0){ out.company=rem[ci]; rem.splice(ci,1); }
    if(rem.length){ out.name=rem[0]; rem.splice(0,1); }
    if(rem.length&&!out.company){ out.company=rem[0]; }
  }
  if(out.address1&&out.city) out.address1=stripTrailingCity(out.address1,out.city);
  return out;
}
function AddressCard({title,data,set,required,residential,setResidential,addresses,onPick,onSave,errorFields=[],contactFallback}){
  const f=(k,v)=>set({...data,[k]:v});
  // Smart paste: if the pasted text parses into 2+ fields, distribute it across the whole form instead of one field
  const onSmartPaste=(e)=>{
    const txt=((e.clipboardData||window.clipboardData)&&(e.clipboardData||window.clipboardData).getData("text"))||"";
    const parsed=parseAddressBlob(txt);
    const keys=Object.keys(parsed).filter(k=>parsed[k]);
    if(keys.length<2) return;   // single value → let the normal paste land in this field
    e.preventDefault();
    set(prev=>{ const next={...prev}; for(const k of keys) next[k]=parsed[k]; return next; });
  };
  const [q,setQ]=useState("");
  const [open,setOpen]=useState(false);
  const [savedOk,setSavedOk]=useState(false);
  // Google Places autocomplete on Address 1
  const [acSug,setAcSug]=useState([]);
  const [acOpen,setAcOpen]=useState(false);
  const [acBusy,setAcBusy]=useState(false);
  const sessionRef=React.useRef(Math.random().toString(36).slice(2));
  const acSkip=React.useRef(false); // skip the autocomplete fetch right after we fill from a pick
  const acFocusRef=React.useRef(false); // only show suggestions while the user is actively in the field
  useEffect(()=>{
    const v=String(data.address1||"").trim();
    if(acSkip.current){acSkip.current=false;return;}
    if(!acFocusRef.current){setAcOpen(false);return;}   // don't auto-open on page load / programmatic fills
    if(v.length<3){setAcSug([]);setAcOpen(false);return;}
    let cancel=false;
    const t=setTimeout(async()=>{
      setAcBusy(true);
      const r=await placesCall({action:"autocomplete",input:v,session:sessionRef.current});
      if(cancel)return;
      setAcBusy(false);
      if(r&&r.ok&&r.predictions&&r.predictions.length&&acFocusRef.current){setAcSug(r.predictions);setAcOpen(true);}
      else {setAcSug([]);setAcOpen(false);}
    },300);
    return ()=>{cancel=true;clearTimeout(t);};
  },[data.address1]);
  const pickPlace=async(p)=>{
    acFocusRef.current=false;setAcOpen(false);setAcSug([]);setAcBusy(true);   // hard-close the dropdown immediately
    const r=await placesCall({action:"details",placeId:p.placeId,session:sessionRef.current});
    setAcBusy(false);
    sessionRef.current=Math.random().toString(36).slice(2);
    if(r&&r.ok&&r.address){
      const a=r.address;acSkip.current=true;
      set(prev=>({...prev,address1:a.address1||prev.address1,city:a.city||prev.city,state:a.state||prev.state,zip:a.zip||prev.zip,country:a.country||prev.country||"United States"}));
    }
  };
  const saveToBook=()=>{ if(onSave){onSave(data);setSavedOk(true);setTimeout(()=>setSavedOk(false),1600);} };
  // Auto-fill city + state when a 5-digit ZIP is entered
  const lastZip=React.useRef("");
  useEffect(()=>{
    const zip=String(data.zip||"").trim();
    if(!/^\d{5}$/.test(zip)||zip===lastZip.current)return;
    lastZip.current=zip;
    let cancel=false;
    const t=setTimeout(()=>{
      fetch("https://api.zippopotam.us/us/"+zip).then(r=>r.ok?r.json():null).then(d=>{
        if(cancel||!d||!d.places||!d.places[0])return;
        const p=d.places[0];
        set(prev=>{ const city=p["place name"]||prev.city; const a1=stripTrailingCity(prev.address1||"", p["place name"]); return {...prev,city,state:p["state abbreviation"]||prev.state,address1:a1}; });
      }).catch(()=>{});
    },400);
    return ()=>{cancel=true;clearTimeout(t);};
  },[data.zip]);
  const matches=(addresses||[]).filter(a=>!q.trim()||[a.name,a.company,a.city,a.zip,a.address1].filter(Boolean).some(v=>String(v).toLowerCase().includes(q.toLowerCase()))).slice(0,12);
  const pick=(a)=>{const cf=contactFallback||{};set({...data,name:a.name||"",company:a.company||"",address1:a.address1||"",address2:a.address2||"",city:a.city||"",state:a.state||"",zip:a.zip||"",country:a.country||data.country||"United States",phone:a.phone||cf.phone||"",email:a.email||cf.email||""});setQ("");setOpen(false);onPick&&onPick(a);};
  // cell() is a plain render helper (NOT a component) so inputs never remount → focus is kept while typing
  const cell=(label,k,span,req)=>(
    <div key={k} className={`px-2 py-1.5 ${errorFields.includes(k)?"bg-rose-50 ring-1 ring-rose-300":(req&&!data[k]?"bg-[#E6F4FF]":"bg-white")} ${span||""} ${k==="address1"?"relative":""}`}>
      <div className={`text-[9px] uppercase tracking-wide ${errorFields.includes(k)?"text-rose-600 font-semibold":(req&&!data[k]?"text-[#0086E0]":"text-stone-400")} flex items-center gap-1`}>{label}{errorFields.includes(k)?" • required":""}{k==="address1"&&acBusy&&<Loader2 className="w-2.5 h-2.5 animate-spin text-stone-400"/>}</div>
      {k==="country"
        ? <select value={data.country||"United States"} onChange={e=>f("country",e.target.value)} className="w-full bg-transparent text-[13px] text-stone-900 outline-none mt-0.5">{COUNTRIES.map(c=><option key={c}>{c}</option>)}</select>
        : <input value={data[k]||""} onChange={e=>f(k,e.target.value)} onPaste={onSmartPaste} onFocus={k==="address1"?()=>{acFocusRef.current=true;if(acSug.length)setAcOpen(true);}:undefined} onBlur={k==="address1"?()=>setTimeout(()=>{acFocusRef.current=false;setAcOpen(false);},150):undefined} autoComplete="off" className="w-full bg-transparent text-[13px] text-stone-900 outline-none mt-0.5 placeholder-stone-300"/>}
      {k==="address1"&&acOpen&&acSug.length>0&&<div className="absolute z-40 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg max-h-60 overflow-auto">
        <div className="px-3 py-1.5 text-[10px] uppercase tracking-widest text-stone-400 bg-stone-50 border-b border-stone-100 flex items-center gap-1"><MapPin className="w-3 h-3"/>Google Maps suggestions</div>
        <div className="divide-y divide-stone-100">
        {acSug.map(p=><button key={p.placeId} onMouseDown={(e)=>{e.preventDefault();pickPlace(p);}} className="w-full text-left px-3 py-2 hover:bg-[#E6F4FF] text-[13px] text-stone-700">{p.description}</button>)}
        </div>
      </div>}
    </div>
  );
  return (<div className="relative">
    <div className="flex items-center justify-between mb-1.5">
      <span className="text-[#0086E0] font-semibold text-sm">{title}</span>
      <div className="flex items-center gap-2">
        {onSave&&<button type="button" onClick={saveToBook} disabled={!data.name&&!data.company} className={`flex items-center gap-1 text-[10px] rounded px-1.5 py-0.5 border ${savedOk?"bg-emerald-50 border-emerald-200 text-emerald-700":"bg-white border-stone-200 text-stone-500 hover:text-[#0086E0] hover:border-[#99D6FF] disabled:opacity-40"}`} title="Save this address to your address book">{savedOk?<><Check className="w-3 h-3"/>Saved</>:<><Plus className="w-3 h-3"/>Save to Address Book</>}</button>}
        {setResidential&&<label className="flex items-center gap-1.5 text-[11px] cursor-pointer"><input type="checkbox" checked={residential} onChange={e=>setResidential(e.target.checked)} className="accent-[#0086E0]"/>{residential?<span className="flex items-center gap-1 text-[#006FBF]"><Home className="w-3.5 h-3.5"/>Residential</span>:<span className="flex items-center gap-1 text-stone-600"><Building2 className="w-3.5 h-3.5"/>Commercial</span>}</label>}
      </div>
    </div>
    {addresses!==undefined&&(
      <div className="relative mb-1.5">
        <Search className="w-3.5 h-3.5 absolute left-2.5 top-2.5 text-stone-400"/>
        <input value={q} onChange={e=>{setQ(e.target.value);setOpen(true);}} onFocus={()=>setOpen(true)} onBlur={()=>setTimeout(()=>setOpen(false),150)} placeholder={(addresses&&addresses.length)?`Address book — ${addresses.length} saved (click to choose)…`:"Address book — empty (use Save to Address Book below)"} className="w-full bg-white border border-stone-200 rounded pl-8 pr-8 py-1.5 text-[13px] outline-none focus:border-[#0099FF] placeholder-stone-300"/>
        <button type="button" onMouseDown={(e)=>{e.preventDefault();setOpen(o=>!o);}} className="absolute right-2 top-1.5 text-stone-400 hover:text-[#0086E0]" title="Show all saved addresses"><ChevronDown className={`w-4 h-4 transition-transform ${open?"rotate-180":""}`}/></button>
        {open&&matches.length===0&&<div className="absolute z-30 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg px-3 py-2.5 text-[12px] text-stone-400">{(addresses&&addresses.length)?"No matches — try fewer letters.":"Nothing saved yet. Fill in an address and hit “Save to Address Book” — it’ll be one click next time."}</div>}
        {open&&matches.length>0&&<div className="absolute z-30 left-0 right-0 top-full mt-1 bg-white border border-stone-200 rounded-lg shadow-lg max-h-64 overflow-auto">
          <div className="px-3 py-1.5 text-[10px] uppercase tracking-widest text-stone-400 bg-stone-50 border-b border-stone-100 sticky top-0">{q.trim()?`${matches.length} match${matches.length===1?"":"es"}`:`${addresses.length} saved address${addresses.length===1?"":"es"}`}</div>
          <div className="divide-y divide-stone-100">
          {matches.map(a=><button key={a.id} onMouseDown={()=>pick(a)} className="w-full text-left px-3 py-2 hover:bg-[#E6F4FF]"><div className="text-sm font-medium text-stone-800">{a.name}{a.company?` · ${a.company}`:""}</div><div className="text-[11px] text-stone-400">{a.address1}{a.address1?", ":""}{a.city} {a.state} {a.zip}{a.acctNum?` · bill ${a.acctCarrier||""} ${a.acctNum}`:""}</div></button>)}
          </div>
        </div>}
      </div>
    )}
    <div className="grid grid-cols-6 gap-px bg-stone-200 border border-stone-200 rounded-lg overflow-hidden">
      {cell("Country","country","col-span-6")}{cell("Name","name","col-span-3",required)}{cell("Company","company","col-span-3")}{cell("Address 1","address1","col-span-6",required)}{cell("Zip","zip","col-span-2",required)}{cell("State","state","col-span-2",required)}{cell("City","city","col-span-2",required)}{cell("Address 2","address2","col-span-3")}{cell("Address 3","address3","col-span-3")}{cell("Phone","phone","col-span-3",required)}{cell("Email","email","col-span-3",required)}
    </div>
  </div>);
}
function PkgInput({label,w,req,...p}){const ww=w||"w-14";const on=req&&!String(p.value??"").trim();return <div className={ww}><div className={`text-[10px] uppercase tracking-widest text-center ${on?"text-[#0086E0]":"text-stone-500"}`}>{label}</div><input placeholder="0" {...p} type="number" className={`w-full border rounded px-2 py-1 text-sm font-mono text-stone-900 outline-none focus:border-[#0099FF] placeholder-stone-300 text-center ${on?"bg-[#E6F4FF] border-[#99D6FF]":"bg-white border-stone-300"}`}/></div>;}
function Panel({title,children}){return <div className="border border-stone-200 rounded-lg bg-white p-4 space-y-3"><div className="text-[11px] uppercase tracking-widest text-stone-400">{title}</div>{children}</div>;}
function Field({label,children}){return <label className="block space-y-1"><span className="text-[11px] text-stone-500">{label}</span>{children}</label>;}
function Input({className="",...p}){return <input {...p} className={`w-full bg-white border border-stone-200 rounded px-2.5 py-2 text-sm font-mono text-stone-900 focus:border-[#0099FF] outline-none ${className}`}/>;}
function Select({children,...p}){return <select {...p} className="w-full bg-white border border-stone-200 rounded px-2.5 py-2 text-sm focus:border-[#0099FF] outline-none">{children}</select>;}
function Toggle({on,set,label}){return <button onClick={()=>set(!on)} className={`flex items-center gap-1.5 text-xs rounded px-2.5 py-1.5 border ${on?"bg-[#E6F4FF] border-[#99D6FF] text-[#0086E0]":"bg-white border-stone-200 text-stone-400"}`}><span className={`w-2 h-2 rounded-full ${on?"bg-[#0086E0]":"bg-stone-300"}`}/>{label}</button>;}
function Badge({children,tone="stone"}){const t={stone:"bg-stone-100 text-stone-500 border-stone-200",green:"bg-emerald-50 text-emerald-700 border-emerald-200",amber:"bg-amber-50 text-amber-700 border-amber-200",blue:"bg-[#E6F4FF] text-[#006FBF] border-[#99D6FF]",rose:"bg-rose-50 text-rose-600 border-rose-200"}[tone];return <span className={`text-[10px] uppercase tracking-wide rounded px-1.5 py-0.5 border ${t}`}>{children}</span>;}
function Empty({icon:Icon,title,body}){return <div className="border border-dashed border-stone-300 rounded-lg p-12 text-center"><Icon className="w-8 h-8 text-stone-300 mx-auto mb-3"/><div className="text-stone-700 font-medium">{title}</div><div className="text-sm text-stone-400 mt-1 max-w-sm mx-auto">{body}</div></div>;}
function EditField({label,v,on}){return <label className="block"><span className="text-[10px] uppercase tracking-wide text-stone-400">{label}</span><input value={v} onChange={e=>on(e.target.value)} className="w-full bg-white border border-stone-200 rounded px-2 py-1 text-sm mt-0.5 outline-none focus:border-[#0099FF]"/></label>;}
function Info({k,v}){return <div className="flex justify-between gap-4 py-0.5 border-b border-stone-100"><span className="text-stone-400">{k}</span><span className="text-stone-800 text-right">{v}</span></div>;}
